from pathlib import Path
import argparse, base64, html, json, re, unicodedata
ROOT=Path(__file__).resolve().parent; BOOKS=ROOT/'books'; OUT=ROOT/'index.html'
TR={'а':'a','б':'b','в':'v','г':'h','ґ':'g','д':'d','е':'e','є':'ie','ж':'zh','з':'z','и':'y','і':'i','ї':'i','й':'i','к':'k','л':'l','м':'m','н':'n','о':'o','п':'p','р':'r','с':'s','т':'t','у':'u','ф':'f','х':'kh','ц':'ts','ч':'ch','ш':'sh','щ':'shch','ь':'','ю':'iu','я':'ia','ы':'y','э':'e','ъ':'','ё':'yo'}
def slug(s):
    s=''.join(TR.get(c,c) for c in s.lower()); s=unicodedata.normalize('NFKD',s); s=''.join(c for c in s if not unicodedata.combining(c)); return re.sub(r'[^a-z0-9]+','-',s).strip('-') or 'book'
def cover_data_url(pdf,zoom=2.2):
    try:
        import fitz, io
        from PIL import Image
        doc=fitz.open(str(pdf)); page=doc.load_page(0); r=page.rect
        clip=fitz.Rect(r.x0+r.width/2,r.y0,r.x1,r.y1)
        pix=page.get_pixmap(matrix=fitz.Matrix(zoom,zoom),clip=clip,alpha=False)
        img=Image.frombytes('RGB',[pix.width,pix.height],pix.samples)
        target=2/3; w,h=img.size
        if w/h>target:
            nw=int(h*target); left=max(0,(w-nw)//2); img=img.crop((left,0,left+nw,h))
        if img.width>760:
            nh=int(img.height*(760/img.width)); img=img.resize((760,nh),Image.LANCZOS)
        buf=io.BytesIO(); img.save(buf,format='JPEG',quality=90,optimize=True)
        return 'data:image/jpeg;base64,'+base64.b64encode(buf.getvalue()).decode('ascii')
    except Exception as e:
        print('Cover skipped for',pdf.name,':',e); return ''
def build_books(author,category,zoom):
    BOOKS.mkdir(exist_ok=True); pdfs=list(BOOKS.glob('*.pdf'))+list(BOOKS.glob('*.PDF')); used=set(); out=[]; covers=0
    for pdf in sorted(pdfs,key=lambda p:p.name.lower()):
        title=pdf.stem.strip(); base=slug(title); ident=base; i=2
        while ident in used: ident=f'{base}-{i}'; i+=1
        used.add(ident); cov=cover_data_url(pdf,zoom); covers+=1 if cov else 0
        out.append({'id':ident,'title':title,'author':author,'category':category,'file':'books/'+pdf.name,'cover':cov,'tags':[]})
    return out,covers
